<template><div class="page-container narrow"><PageHeader eyebrow="ACCOUNT" title="个人中心" description="管理个人资料与账户安全"/><el-tabs v-model="tab" class="surface-tabs"><el-tab-pane label="个人资料" name="profile"><el-form :model="profile" label-position="top" class="form-grid"><el-form-item label="用户名"><el-input :model-value="profile.username" disabled/></el-form-item><el-form-item label="邮箱"><el-input v-model="profile.email"/></el-form-item><el-form-item label="昵称"><el-input v-model="profile.nickname"/></el-form-item><el-form-item label="头像地址"><el-input v-model="profile.avatarUrl"/></el-form-item><el-form-item label="个人简介" class="form-span"><el-input v-model="profile.bio" type="textarea" :rows="4"/></el-form-item><div class="form-span"><el-button type="primary" @click="save">保存资料</el-button></div></el-form></el-tab-pane><el-tab-pane label="修改密码" name="password"><el-form :model="password" label-position="top" class="password-form"><el-form-item label="旧密码"><el-input v-model="password.oldPassword" type="password" show-password/></el-form-item><el-form-item label="新密码"><el-input v-model="password.newPassword" type="password" show-password/></el-form-item><el-button type="primary" @click="changePassword">更新密码</el-button></el-form></el-tab-pane></el-tabs></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import { ElMessage } from 'element-plus';import { userApi } from '../../api/user';import { authStore } from '../../stores/auth';const tab=ref('profile'),profile=reactive({}),password=reactive({oldPassword:'',newPassword:''});onMounted(async()=>Object.assign(profile,await userApi.me()));async function save(){const data=await userApi.updateMe({email:profile.email,nickname:profile.nickname,avatarUrl:profile.avatarUrl,bio:profile.bio});Object.assign(profile,data);authStore.persist(data);ElMessage.success('资料已更新')}async function changePassword(){await userApi.changePassword(password);ElMessage.success('密码修改成功');password.oldPassword='';password.newPassword=''}</script>
